import { Fragment } from 'react';
import { Helmet } from 'react-helmet';
import Image from 'components/Image';
import { useScrollRestore } from 'hooks';
import Footer from 'components/Footer';
import {
  ProjectContainer,
  ProjectSection,
  ProjectSectionContent,
  ProjectImage,
  ProjectTextRow,
  ProjectSectionHeading,
  ProjectSectionText,
  ProjectBackground,
  ProjectHeader,
} from 'components/ProjectLayout';
import sliceBackground from 'assets/cleverdata.png';
import sliceBackgroundLarge from 'assets/cleverdata.png';
import sliceBackgroundPlaceholder from 'assets/slice-background-placeholder.jpg';
import sliceApp from 'assets/connections.png';
import sliceAppLarge from 'assets/connections.png';
import sliceAppPlaceholder from 'assets/slice-app-placeholder.jpg';
import sliceSlides from 'assets/onboarding.png';
import sliceSlidesLarge from 'assets/onboarding.png';
import sourcesSlidesLarge from 'assets/sources.png';
import sourcesSlides from 'assets/sources.png';
import bodySlides from 'assets/body.png';
import bodySlidesLarge from 'assets/body.png';
import sliceSlidesPlaceholder from 'assets/slice-slides-placeholder.jpg';
import prerender from 'utils/prerender';
import { media } from 'utils/style';
import './index.css';

const title = 'DMP & Data Exchange';
const description =
  'Продукт представляет из себя ядро всей инфраструктуры монетизации данных для компаний, ориентированных на работу с данными и построения собственной Платформы управления данными.';
const roles = ['Frontend разработка', 'UX дизайн', 'Архитектура'];

const ProjectSlice = () => {
  useScrollRestore();

  return (
    <Fragment>
      <Helmet>
        <title>{`Projects | ${title}`}</title>
        <meta name="description" content={description} />
      </Helmet>
      <ProjectContainer className="slice">
        <ProjectBackground
          srcSet={`${sliceBackground} 1280w, ${sliceBackgroundLarge} 2560w`}
          placeholder={sliceBackgroundPlaceholder}
          opacity={0.8}
          entered={!prerender}
        />
        <ProjectHeader
          title={title}
          description={description}
          url="https://cleverdata.ru/"
          roles={roles}
        />
        <ProjectSection first>
          <ProjectSectionContent>
            <ProjectImage
              srcSet={`${sliceApp} 800w, ${sliceAppLarge} 1920w`}
              placeholder={sliceAppPlaceholder}
              alt="The Slice web application showing a selected user annotation."
              sizes={`(max-width: ${media.mobile}px) 100vw, (max-width: ${media.tablet}px) 90vw, 80vw`}
            />
          </ProjectSectionContent>
        </ProjectSection>
        <ProjectSection light>
          <ProjectSectionContent>
            <ProjectTextRow>
              <ProjectSectionHeading>Переезд</ProjectSectionHeading>
              <ProjectSectionText>
                Задачей нашей команды стал переезд на современные технологии. Перевод многострочного легаси-кода с Angular на React, согласование дизайна. В переписывании проектов есть приятные мелочи. Можно выбрать удобные пакеты и технологии. Например, вместо Redux была выбрана RTK Query. Библиотека на порядок сократила количество бойлерплейта.
              </ProjectSectionText>
              <ProjectSectionText>
                Также, наше решение было построено по архитектурному принципу Module Federation. А вишенкой на торте стала кубернетизация модулей и переезд в Yandex Cloud
              </ProjectSectionText>
            </ProjectTextRow>
            <Image
              srcSet={`${sliceSlides} 800w, ${sliceSlidesLarge} 1440w`}
              placeholder={sliceSlidesPlaceholder}
              alt="The new My Slides tab in slice, showing annotated and favorited slides."
              sizes={`(max-width: ${media.mobile}px) 500px, (max-width: ${media.tablet}px) 800px, 1000px`}
            />
          </ProjectSectionContent>
        </ProjectSection>
        <ProjectSection light>
          <ProjectSectionContent>
            <ProjectTextRow>
              <ProjectSectionHeading>Задачи</ProjectSectionHeading>
              <ProjectSectionText>
                <ul>
                  <li>Разработка/доработка функционала Angular версии продукта DMP</li>
                  <li>Перевод проекта на React</li>
                  <li>Архитектура клиентской части проекта</li>
                  <li>UX Design</li>
                </ul>
              </ProjectSectionText>
            </ProjectTextRow>
            <Image
              srcSet={`${sourcesSlides} 800w, ${sourcesSlidesLarge} 1440w`}
              placeholder={sliceSlidesPlaceholder}
              alt="The new My Slides tab in slice, showing annotated and favorited slides."
              sizes={`(max-width: ${media.mobile}px) 500px, (max-width: ${media.tablet}px) 800px, 1000px`}
            />
          </ProjectSectionContent>
        </ProjectSection>
        <ProjectSection light>
          <ProjectSectionContent>
            <ProjectTextRow>
              <ProjectSectionHeading>Достижения</ProjectSectionHeading>
              <ProjectSectionText>
                <ul>
                  <li>Заложена архитектура Module Federation</li>
                  <li>В сжатые сроки реализовал основные модули для выпуска MVP</li>
                  <li>Завёл пространство в Conflunce, написал документацию и инструкции</li>
                  <li>Оптимизировал процесс согласования дизайна и предложил изменения расписания митингов и встреч</li>
                </ul>
              </ProjectSectionText>
            </ProjectTextRow>
            <Image
              srcSet={`${bodySlides} 800w, ${bodySlidesLarge} 1440w`}
              placeholder={sliceSlidesPlaceholder}
              alt="The new My Slides tab in slice, showing annotated and favorited slides."
              sizes={`(max-width: ${media.mobile}px) 500px, (max-width: ${media.tablet}px) 800px, 1000px`}
            />
          </ProjectSectionContent>
        </ProjectSection>
      </ProjectContainer>
      <Footer />
    </Fragment>
  );
};

export default ProjectSlice;
